where.trim:
a.recovery=0
and a.id = #{id}
and a.type = #{type}
and a.type  <>  #{not_type}
and a.store_id = #{store_id}
and a.is_show = #{isShow}
and a.mch_id = #{mchId}
and a.mch_id  <>  #{not_mchId}
and a.is_settlement = #{is_settlement}
and a.status = #{status}
and a.name = #{SpecialName}
and a.recovery = #{recovery}
and (a.id = #{keyName} or a.name like concat('%',#{keyName},'%') or c.name
    like concat('%',#{keyName},'%') )

and a.start_date   >=   #{startDate}
and a.end_date   <=   #{endDate}
and a.add_date   >=  
    #{startDate_sign}

and a.sign_end_date   <=  
    #{endDate_sign}


    
        #{status,jdbcType=INTEGER}
    

and (select ifnull(count(distinct c.id),0) from lkt_auction_session b,lkt_auction_product c where b.special_id=a.id and b.id=c.session_id and a.recovery=0 and a.recovery=b.recovery and a.recovery=c.recovery)  >  #{gt_goods_num}

mapper.select:
SELECT a.id,a.store_id,a.mch_id,a.name,a.img,a.promise_amt,a.look_count,m.name as mch_name,m.head_img as mch_logo, DATE_FORMAT(a.start_date, '%Y-%m-%d %H:%i:%s') as start_date, DATE_FORMAT(a.end_date, '%Y-%m-%d %H:%i:%s') as end_date, DATE_FORMAT(a.sign_end_date, '%Y-%m-%d %H:%i:%s') as sign_end_date, DATE_FORMAT(a.add_date, '%Y-%m-%d %H:%i:%s') as add_date, a.is_show,a.status,a.type,a.mark_up_amt,a.content, (SELECT COUNT(x.id) FROM lkt_auction_remind x WHERE x.special_id = a.id) AS focus_num FROM lkt_auction_special a left join lkt_mch m on a.mch_id = m.id
a.sort desc, a.add_date ${add_date_sort}, a.end_date ${end_date}, a.start_date ${date}, focus_num ${focus_num}, a.look_count ${look_count},
limit #{pageStart},#{pageEnd}

where.trim:
a.recovery=0 and a.mch_id=c.id
and a.id = #{id}
and a.type = #{type}
and a.store_id = #{store_id}
and a.mch_id = #{mchId}
and a.is_show = #{specialShow}

    and EXISTS(select distinct a1.id from lkt_auction_special a1
    LEFT JOIN lkt_auction_session b1
    ON a1.id=b1.special_id
    LEFT JOIN lkt_auction_product c1
    ON c1.session_id = b1.id
    LEFT JOIN lkt_product_list d1
    ON d1.id=c1.goods_id
    WHERE a1.recovery=a.recovery and c1.recovery=a.recovery and a1.store_id = a.store_id and a1.type = a.type and d1.mch_id = #{myMchId} and a1.id=a.id)

and a.status = #{status}
and a.name = #{SpecialName}
and (a.id = #{keyName} or a.name like concat('%',#{keyName},'%') or c.name
    like concat('%',#{keyName},'%') )

and a.start_date   >=   #{startDate}
and a.end_date   <=   #{endDate}

    
        #{status,jdbcType=INTEGER}
    


    
        #{status,jdbcType=INTEGER}

mapper.select:
SELECT a.id, a.`number`, a.name, a.start_date, a.end_date, a.sign_end_date, a.promise_amt, a.`status`, a.mchName, a.commission, a.img, a.content, a.isShow, a.`cunit`, a.type, a.mark_up_amt, a.sessionNum, a.sort FROM ( SELECT a.id, a.number AS `number`, a.name, a.start_date, a.sort, a.end_date, a.sign_end_date, a.promise_amt, a.`status`, c.`name` mchName, a.commission, a.img, a.content, a.is_show isShow, a.`unit` AS `cunit`, a.type, a.mark_up_amt, ( SELECT count( x.id ) FROM lkt_auction_session x WHERE x.special_id = a.id AND x.recovery = 0 ) AS sessionNum, ROW_NUMBER() over(partition by a.id) as top FROM lkt_auction_special a LEFT JOIN lkt_auction_session b ON a.id = b.special_id AND a.recovery = b.recovery, lkt_mch c
a.add_date ${add_date_sort},
)as a where a.top <2 limit #{pageStart},#{pageEnd}

where.trim:
a.id=b.pid and a.recycle=0 and b.recycle=a.recycle and substring_index(substring_index(a.product_class,
'-', 2), '-', -1)=c.cid
and a.store_id = #{store_id}
and a.active = #{active}
and a.mch_id = #{mchId}
AND a.product_class like CONCAT('%-',#{classId},'-%')
and ( a.id=#{key} or a.product_title like concat('%',#{key},'%') )

mapper.select:
select a.id,b.id attrId,a.product_title,c.pname,b.price,b.size,b.img from lkt_product_list a,lkt_configure b,lkt_product_class c
a.add_date ${add_date_sort},
limit #{pageStart},#{pageEnd}

where.trim:
                and a.recovery=0
                and a.store_id = #{store_id}
                and a.mch_id = #{shopId}

                and a.id = #{specialId}
                and a.status = #{status}
                and a.type = #{type}
                and a.is_show = #{isShow}
                
                    and not EXISTS(select distinct a1.id from lkt_auction_special a1
                    LEFT JOIN lkt_auction_session b1
                    ON a1.id=b1.special_id
                    LEFT JOIN lkt_auction_product c1
                    ON c1.session_id = b1.id
                    LEFT JOIN lkt_product_list d1
                    ON d1.id=c1.goods_id
                    WHERE a1.recovery=a.recovery and c1.recovery=a.recovery and a1.store_id = a.store_id and a1.type = a.type and d1.mch_id = #{not_sign} and a1.id=a.id)
                
                
                    and EXISTS(select distinct a1.id from lkt_auction_special a1
                    LEFT JOIN lkt_auction_session b1
                    ON a1.id=b1.special_id
                    LEFT JOIN lkt_auction_product c1
                    ON c1.session_id = b1.id
                    LEFT JOIN lkt_product_list d1
                    ON d1.id=c1.goods_id
                    WHERE a1.recovery=a.recovery and c1.recovery=a.recovery and a1.store_id = a.store_id and a1.type = a.type and d1.mch_id = #{signing} and a1.id=a.id)
                
                and a.sign_end_date   >   #{gt_sign}
                and a.sign_end_date   <   #{lt_sign}
                and a.start_date   >=   #{gt_sign}
                and a.end_date   <=   #{lt_sign}

mapper.select:
select distinct a.id,a.mch_id,a.name,a.add_date,a.sign_end_date,a.status,a.img,a.mark_up_amt,a.number,a.unit,a.commission from lkt_auction_special a
a.add_date ${add_date_sort},
limit #{pageStart},#{pageEnd}

        SELECT COUNT(*) AS total_num
        FROM (

                 SELECT d.auction_id
                 FROM lkt_auction_special a
                          INNER JOIN lkt_auction_session b ON a.id = b.special_id AND a.recovery = b.recovery
                          INNER JOIN lkt_auction_product c ON b.id = c.session_id AND a.recovery = c.recovery
                          INNER JOIN lkt_auction_record d ON c.id = d.auction_id
                 WHERE a.mch_id = #{mchId}
                   AND a.recovery = 0
                   AND c.status = #{status}
                 GROUP BY d.auction_id
             ) AS t;
